#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char X[M + 1], Y[M + 1];
        scanf("%s %s", X, Y);
        long long dp[N + 1];
        dp[0] = 1;
        for (int i = 1; i <= N; i++) {
            dp[i] = (25 * dp[i - 1]) % MOD;
            if (i >= M) {
                char substr[M + 1];
                strncpy(substr, X, M);
                substr[M] = '\0';
                if (strcmp(substr, X) >= 0 && strcmp(substr, Y) <= 0) {
                    dp[i] = (dp[i] - dp[i - M]) % MOD;
                    if (dp[i] < 0) dp[i] += MOD;
                }
            }
        }
        printf("%lld\n", dp[N]);
    }
    return 0;
}

