import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            String X = sc.next();
            String Y = sc.next();
            long[] dp = new long[N + 1];
            dp[0] = 1;
            final int MOD = 1000000007;
            for (int i = 1; i <= N; i++) {
                dp[i] = (25 * dp[i - 1]) % MOD;
                if (i >= M) {
                    String substr = X;
                    if (X.compareTo(substr) <= 0 && substr.compareTo(Y) <= 0) {
                        dp[i] = (dp[i] - dp[i - M]) % MOD;
                        if (dp[i] < 0) dp[i] += MOD;
                    }
                }
            }
            System.out.println(dp[N]);
        }
    }
}

